// Проверяем что данные получены и трансформируем для PostgreSQL
const items = $input.all();

// Если ошибка - возвращаем пустой массив
if (!items || items.length === 0 || items[0].json.error) {
  console.log('⚠️ Vehicles: No data or error');
  return [];
}

// Если данные вложены в массив
let vehicles = items;
if (items[0].json && Array.isArray(items[0].json)) {
  vehicles = items[0].json.map(v => ({ json: v }));
}

const result = [];
for (const item of vehicles) {
  const v = item.json;
  result.push({
    json: {
      id: String(v.id || v.Ref_Key || '').trim(),
      license_plate: String(v.license_plate || v.ГосНомер || v.RegNumber || '').trim(),
      model: String(v.model || v.Модель || v.Model || v.Description || 'Неизвестно').trim()
    }
  });
}

console.log(`✅ Vehicles: ${result.length} records`);
return result;

// Проверяем что данные получены и трансформируем для PostgreSQL
const items = $input.all();

if (!items || items.length === 0 || items[0].json.error) {
  console.log('⚠️ Drivers: No data or error');
  return [];
}

let drivers = items;
if (items[0].json && Array.isArray(items[0].json)) {
  drivers = items[0].json.map(d => ({ json: d }));
}

const result = [];
for (const item of drivers) {
  const d = item.json;
  result.push({
    json: {
      id: String(d.id || d.Ref_Key || d.full_name || '').trim(),
      full_name: String(d.full_name || d.ФИО || d.Description || d.name || 'Неизвестно').trim()
    }
  });
}

console.log(`✅ Drivers: ${result.length} records`);
return result;

// Трансформация контрактов с безопасным экранированием
const items = $input.all();

if (!items || items.length === 0 || items[0].json.error) {
  console.log('⚠️ Contracts: No data or error');
  return [];
}

let contracts = items;
if (items[0].json && Array.isArray(items[0].json)) {
  contracts = items[0].json.map(c => ({ json: c }));
}

// Функция для безопасного экранирования строк
function esc(val) {
  if (val === null || val === undefined) return null;
  return String(val).replace(/'/g, "''");
}

const result = [];
for (const item of contracts) {
  const c = item.json;
  result.push({
    json: {
      number: esc(c.number || c.Номер),
      date: c.date || c.Дата,
      organization: esc(c.organization || c.Организация || ''),
      contractor_id: esc(c.contractor_id || c.Контрагент_Key || ''),
      contractor_name: esc(c.contractor_name || c.Контрагент || ''),
      vehicle_id: esc(c.vehicle_id || c.ТС_Key || ''),
      vehicle_number: esc(c.vehicle_number || c.ГосНомер || ''),
      driver_id: esc(c.driver_id || c.Водитель_Key || ''),
      driver_name: esc(c.driver_name || c.Водитель || ''),
      responsible_logist: esc(c.responsible_logist || c.ОтветственныйЛогист || ''),
      route: esc(c.route || c.Маршрут || ''),
      payment_term: esc(c.payment_term || c.УсловияОплаты || ''),
      payment_condition: esc(c.payment_condition || c.СрокОплаты || ''),
      amount: parseFloat(c.amount || c.Сумма || 0) || 0
    }
  });
}

console.log(`✅ Contracts: ${result.length} records`);
return result;

// Трансформация отчётов водителей
const items = $input.all();

if (!items || items.length === 0 || items[0].json.error) {
  console.log('⚠️ Driver Reports: No data or error');
  return [];
}

let reports = items;
if (items[0].json && Array.isArray(items[0].json)) {
  reports = items[0].json.map(r => ({ json: r }));
}

function esc(val) {
  if (val === null || val === undefined) return null;
  return String(val).replace(/'/g, "''");
}

const result = [];
for (const item of reports) {
  const r = item.json;
  result.push({
    json: {
      id: esc(r.id || r.Ref_Key),
      number: esc(r.number || r.Номер),
      date_from: r.date_from || r.ДатаНачала,
      date_to: r.date_to || r.ДатаОкончания,
      driver_id: esc(r.driver_id || r.Водитель_Key || ''),
      driver_name: esc(r.driver_name || r.Водитель || ''),
      vehicle_id: esc(r.vehicle_id || r.ТС_Key || ''),
      vehicle_number: esc(r.vehicle_number || r.ГосНомер || ''),
      fuel_start: parseFloat(r.fuel_start || r.ТопливоНачало || 0) || 0,
      fuel_end: parseFloat(r.fuel_end || r.ТопливоКонец || 0) || 0,
      mileage: parseFloat(r.mileage || r.Пробег || 0) || 0,
      fuel_quantity: parseFloat(r.fuel_quantity || r.КоличествоТоплива || 0) || 0,
      fuel_amount: parseFloat(r.fuel_amount || r.СуммаТоплива || 0) || 0,
      total_expenses: parseFloat(r.total_expenses || r.ВсегоРасходы || 0) || 0,
      driver_accruals: parseFloat(r.driver_accruals || r.НачисленоВодителю || 0) || 0,
      driver_payments: parseFloat(r.driver_payments || r.ВыплаченоВодителю || 0) || 0,
      expense_categories: r.expense_categories || r.КатегорииРасходов || []
    }
  });
}

console.log(`✅ Driver Reports: ${result.length} records`);
return result;

// Извлекаем категории расходов из отчётов водителей
const items = $input.all();
const result = [];

for (const item of items) {
  const reportId = item.json.id;
  const categories = item.json.expense_categories || [];

  if (Array.isArray(categories)) {
    for (const cat of categories) {
      result.push({
        json: {
          driver_report_id: reportId,
          category: String(cat.category || cat.Категория || '').replace(/'/g, "''"),
          amount: parseFloat(cat.amount || cat.Сумма || 0) || 0
        }
      });
    }
  }
}

console.log(`✅ Expense Categories: ${result.length} records`);
return result;

// Собираем статистику синхронизации
const stats = {
  sync_time: new Date().toISOString(),
  vehicles: 0,
  drivers: 0,
  contracts: 0,
  driver_reports: 0,
  expense_categories: 0,
  errors: []
};

try {
  // Получаем данные из предыдущих нодов
  const vehiclesData = $('Transform: Vehicles').all();
  const driversData = $('Transform: Drivers').all();
  const contractsData = $('Transform: Contracts').all();
  const reportsData = $('Transform: Driver Reports').all();
  const categoriesData = $('Extract: Expense Categories').all();

  stats.vehicles = vehiclesData.length;
  stats.drivers = driversData.length;
  stats.contracts = contractsData.length;
  stats.driver_reports = reportsData.length;
  stats.expense_categories = categoriesData.length;

} catch (e) {
  stats.errors.push(e.message);
}

stats.status = stats.errors.length === 0 ? 'SUCCESS' : 'PARTIAL';
stats.total_records = stats.vehicles + stats.drivers + stats.contracts + stats.driver_reports + stats.expense_categories;

console.log('📊 Sync Report:', JSON.stringify(stats, null, 2));

return [{ json: stats }];

